#include <bits/stdc++.h>using namespace std;typedef long long ll; int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int t;    cin >> t;    while(t--) {        ll n, k;        cin >> n >> k;        vector<ll> a(n);        vector<ll> b(n);        vector<ll> pos(n + 1);        for(int i = 0; i < n; i++) {            cin >> a[i];            pos[a[i]] = i;        }        for(int i = 0; i < n; i++) {            cin >> b[i];        }        ll l = n - k + 1;          ll r = k;                   vector<int> vis(n + 1, 0);        bool f = true;        for(int i = 0; i < n; i++) {            if(i < l - 1 || i > r - 1) {                if(b[i] != -1 && b[i] != a[i]) {                    f = false;                    break;                }            }             else {                if(b[i] != -1) {                    if(b[i] < 1 || b[i] > n) {                        f = false;                        break;                    }                    if(pos[b[i]] < l - 1 || pos[b[i]] > r - 1){                        f = false;                        break;                    }                    if(vis[b[i]]) {                        f = false;                        break;                    }                    vis[b[i]] = 1;                }            }        }        if(f) cout << "YES" << endl;        else cout << "NO" << endl;    }    return 0;}